// src/components/reminder-card/index.tsx
import { useState } from "react";
import { View, Text, Switch, Picker } from "@tarojs/components";
import Taro from "@tarojs/taro";
import { apiFetch } from "../../lib";
import "./index.scss";

interface ReminderCardProps {
  initialEnabled?: boolean;
  initialTime?: string;
  initialDays?: number[];
}

const WEEKDAYS = [
  { label: "周一", value: 1 },
  { label: "周二", value: 2 },
  { label: "周三", value: 3 },
  { label: "周四", value: 4 },
  { label: "周五", value: 5 },
  { label: "周六", value: 6 },
  { label: "周日", value: 7 },
];

export default function ReminderCard({ initialEnabled = false, initialTime = "21:00", initialDays = [1,2,3,4,5,6,7] }: ReminderCardProps) {
  const [enabled, setEnabled] = useState(initialEnabled);
  const [time, setTime] = useState(initialTime);
  const [days, setDays] = useState<number[]>(initialDays);

  async function handleToggle(value: boolean) {
    if (value) {
      // First enable: request subscription
      try {
        const subRes = await Taro.requestSubscribeMessage({
          tmplIds: ["placeholder_template_id"],
        });
        // The response contains keys for each tmplId with values "accept", "reject", "ban"
        const templateResult = subRes["placeholder_template_id"];
        if (templateResult !== "accept") {
          Taro.showToast({ title: "需要授权才能开启每日提醒", icon: "none" });
          return;
        }
      } catch (e) {
        Taro.showToast({ title: "授权失败，请稍后重试", icon: "none" });
        return;
      }
    }

    // Toggle and save
    setEnabled(value);
    await saveReminderState(value, time, days);
  }

  async function handleTimeChange(e: any) {
    const newTime = e.detail.value;
    setTime(newTime);
    if (enabled) {
      await saveReminderState(enabled, newTime, days);
    }
  }

  function toggleDay(day: number) {
    const newDays = days.includes(day)
      ? days.filter(d => d !== day)
      : [...days, day];
    setDays(newDays);
    if (enabled) {
      saveReminderState(enabled, time, newDays);
    }
  }

  async function saveReminderState(enabled: boolean, time: string, days: number[]) {
    await apiFetch("/api/profile/reminder", {
      method: "POST",
      body: JSON.stringify({ enabled, time, days }),
    });
    Taro.showToast({ title: enabled ? "提醒已开启" : "提醒已关闭", icon: "success" });
  }

  const daysLabel = days.length === 7 ? "每天" : days.map(d => WEEKDAYS.find(w => w.value === d)?.label).join("、");

  return (
    <View className="reminder-card">
      <View className="reminder-header">
        <View className="reminder-title-row">
          <Text className="reminder-icon">⏰</Text>
          <Text className="reminder-title">每日打卡提醒</Text>
        </View>
        <Switch
          checked={enabled}
          onChange={(e) => handleToggle(e.detail.value)}
          color="#c4843e"
        />
      </View>

      {enabled && (
        <View className="reminder-body">
          <View className="reminder-row">
            <Text className="reminder-label">提醒时间</Text>
            <Picker mode="time" value={time} onChange={handleTimeChange}>
              <View className="reminder-value">
                <Text>{time}</Text>
                <Text className="reminder-arrow">></Text>
              </View>
            </Picker>
          </View>
          <View className="reminder-row">
            <Text className="reminder-label">重复</Text>
            <View className="reminder-days">
              {WEEKDAYS.map(w => (
                <Text
                  key={w.value}
                  className={`reminder-day ${days.includes(w.value) ? "active" : ""}`}
                  onClick={() => toggleDay(w.value)}
                >
                  {w.label}
                </Text>
              ))}
            </View>
          </View>
          <Text className="reminder-summary">将在每天 {time} 发送打卡提醒</Text>
        </View>
      )}
    </View>
  );
}
```

