```tsx
// src/components/reminder-card/index.tsx
import { useState } from "react";
import { View, Text, Switch, Picker } from "@tarojs/components";
import Taro from "@tarojs/taro";
import { apiFetch } from "../../lib";
import "./index.scss";

const WEEKDAYS = [
  { label: "周一", value: 1 },
  { label: "周二", value: 2 },
  { label: "周三", value: 3 },
  { label: "周四", value: 4 },
  { label: "周五", value: 5 },
  { label: "周六", value: 6 },
  { label: "周日", value: 7 },
];

interface ReminderCardProps {
  initialEnabled?: boolean;
  initialTime?: string;
  initialDays?: number[];
}

export default function ReminderCard({
  initialEnabled = false,
  initialTime = "21:00",
  initialDays = [1, 2, 3, 4, 5, 6, 7],
}: ReminderCardProps) {
  const [enabled, setEnabled] = useState(initialEnabled);
  const [time, setTime] = useState(initialTime);
  const [days, setDays] = useState(initialDays);

  async function handleToggle(value: boolean) {
    if (value) {
      try {
        const res = await Taro.requestSubscribeMessage({
          tmplIds: [SUBSCRIPTION_TEMPLATE_ID],
        });
        if (res[SUBSCRIPTION_TEMPLATE_ID] !== "accept") {
          Taro.showToast({ title: "需要授权才能开启每日提醒", icon: "none" });
          return;
        }
      } catch {
        Taro.showToast({ title: "授权失败，请稍后重试", icon: "none" });
        return;
      }
    }
    setEnabled(value);
    await saveToBackend(value, time, days);
    Taro.showToast({
      title: value ? "提醒已开启" : "提醒已关闭",
      icon: "success",
    });
  }

  async function handleTimeChange(e: any) {
    const newTime = e.detail.value;
    setTime(newTime);
    if (enabled) {
      await saveToBackend(true, newTime, days);
    }
  }

  function toggleDay(dayValue: number) {
    const newDays = days.includes(dayValue)
      ? days.filter((d) => d !== dayValue)
      : [...days, dayValue];
    setDays(newDays);
    if (enabled) {
      saveToBackend(true, time, newDays);
    }
  }

  async function saveToBackend(e: boolean, t: string, d: number[]) {
    await apiFetch("/api/profile", {
      method: "POST",
      body: JSON.stringify({ reminder: { enabled: e, time: t, days: d } }),
    });
  }

  const daysLabel =
    days.length === 7
      ? "每天"
      : days
          .map((d) => WEEKDAYS.find((w) => w.value === d)?.label)
          .filter(Boolean)
          .join("、");

  return (
    <View className="card reminder-card">
      <View className="reminder-header">
        <View className="reminder-title-row">
          <Text className="reminder-icon">⏰</Text>
          <Text className="card-title reminder-title-text">每日打卡提醒</Text>
        </View>
        <Switch
          checked={enabled}
          color="#c4843e"
          className="reminder-switch"
          onChange={(e) => handleToggle(e.detail.value)}
        />
      </View>

      {enabled && (
        <View className="reminder-body">
          <View className="reminder-row">
            <Text className="reminder-label">提醒时间</Text>
            <Picker mode="time" value={time} onChange={handleTimeChange}>
              <View className="reminder-value">
                <Text>{time}</Text>
                <Text className="reminder-arrow">›</Text>
              </View>
            </Picker>
          </View>

          <View className="reminder-row">
            <Text className="reminder-label">重复</Text>
            <View className="reminder-days">
              {WEEKDAYS.map((w) => (
                <Text
                  key={w.value}
                  className={`reminder-day${days.includes(w.value) ? " active" : ""}`}
                  onClick={() => toggleDay(w.value)}
                >
                  {w.label}
                </Text>
              ))}
            </View>
          </View>

          <Text className="reminder-summary">
            将在每天 {time} 发送打卡提醒
          </Text>
        </View>
      )}
    </View>
  );
}
```

