import { View, Text, Switch, Picker } from "@tarojs/components";
import "./index.scss";

const WEEKDAYS = [
  { label: "周一", value: 1 },
  { label: "周二", value: 2 },
  { label: "周三", value: 3 },
  { label: "周四", value: 4 },
  { label: "周五", value: 5 },
  { label: "周六", value: 6 },
  { label: "周日", value: 7 },
];

interface ReminderCardProps {
  enabled: boolean;
  time: string;
  days: number[];
  onToggle: (value: boolean) => void;
  onTimeChange: (time: string) => void;
  onDayToggle: (day: number) => void;
}

export default function ReminderCard({
  enabled,
  time,
  days,
  onToggle,
  onTimeChange,
  onDayToggle,
}: ReminderCardProps) {
  const daysLabel =
    days.length === 7
      ? "每天"
      : days
          .map((d) => WEEKDAYS.find((w) => w.value === d)?.label)
          .filter(Boolean)
          .join("、");

  return (
    <View className="card reminder-card">
      <View className="reminder-header">
        <View className="reminder-title-row">
          <Text className="reminder-icon">⏰</Text>
          <Text className="card-title reminder-title-text">每日打卡提醒</Text>
        </View>
        <Switch
          checked={enabled}
          color="#c4843e"
          className="reminder-switch"
          onClick={(e) => {
            // We handle the toggle in onChange, but onClick keeps it as a simple UI
          }}
          onChange={(e) => onToggle(e.detail.value)}
        />
      </View>

      {enabled && (
        <View className="reminder-body">
          <View className="reminder-row">
            <Text className="reminder-label">提醒时间</Text>
            <Picker mode="time" value={time} onChange={(e) => onTimeChange(e.detail.value)}>
              <View className="reminder-value">
                <Text>{time}</Text>
                <Text className="reminder-arrow">›</Text>
              </View>
            </Picker>
          </View>

          <View className="reminder-row">
            <Text className="reminder-label">重复</Text>
            <View className="reminder-days">
              {WEEKDAYS.map((w) => (
                <Text
                  key={w.value}
                  className={`reminder-day${days.includes(w.value) ? " active" : ""}`}
                  onClick={() => onDayToggle(w.value)}
                >
                  {w.label}
                </Text>
              ))}
            </View>
          </View>

          <Text className="reminder-summary">
            将在 {daysLabel} {time} 发送打卡提醒
          </Text>
        </View>
      )}
    </View>
  );
}
```

