export default function ProfilePage() {
  const [profile, setProfile] = useState({
    name: "", goals: "", wakeTime: "07:00", sleepTime: "23:00", customPrompt: "",
  });
  const [inputs, setInputs] = useState<{ category: string; content: string }[]>([]);
  const [newInput, setNewInput] = useState({ category: "健身", content: "" });
  const [saved, setSaved] = useState(false);

  // Reminder state
  const [reminderEnabled, setReminderEnabled] = useState(false);
  const [reminderTime, setReminderTime] = useState("21:00");
  const [reminderDays, setReminderDays] = useState<number[]>([1, 2, 3, 4, 5, 6, 7]);

  useDidShow(() => {
    apiFetch("/api/profile").then((data) => {
      if (data.profile) {
        setProfile({
          name: data.profile.name || "",
          goals: Array.isArray(data.profile.goals) ? data.profile.goals.join("\n") : "",
          wakeTime: data.profile.wakeTime || "07:00",
          sleepTime: data.profile.sleepTime || "23:00",
          customPrompt: data.profile.preferences?.customPrompt || "",
        });
        // Load reminder settings
        const reminder = data.profile.reminder || {};
        setReminderEnabled(reminder.enabled || false);
        setReminderTime(reminder.time || "21:00");
        setReminderDays(reminder.days || [1, 2, 3, 4, 5, 6, 7]);
      }
      if (data.inputs) setInputs(data.inputs);
    });
  });

  async function saveReminder(enabled: boolean, time: string, days: number[]) {
    await apiFetch("/api/profile", {
      method: "POST",
      body: JSON.stringify({ reminder: { enabled, time, days } }),
    });
  }

  async function handleReminderToggle(value: boolean) {
    if (value) {
      try {
        const res = await Taro.requestSubscribeMessage({
          tmplIds: [REMINDER_TEMPLATE_ID],
        });
        if (res[REMINDER_TEMPLATE_ID] !== "accept") {
          Taro.showToast({ title: "需要授权才能开启每日提醒", icon: "none" });
          return;
        }
      } catch {
        Taro.showToast({ title: "授权失败，请稍后重试", icon: "none" });
        return;
      }
    }
    setReminderEnabled(value);
    await saveReminder(value, reminderTime, reminderDays);
    Taro.showToast({
      title: value ? "每日提醒已开启" : "每日提醒已关闭",
      icon: "success",
    });
  }

  async function handleReminderTimeChange(time: string) {
    setReminderTime(time);
    if (reminderEnabled) {
      await saveReminder(true, time, reminderDays);
    }
  }

  function handleReminderDayToggle(day: number) {
    const newDays = reminderDays.includes(day)
      ? reminderDays.filter((d) => d !== day)
      : [...reminderDays, day];
    setReminderDays(newDays);
    if (reminderEnabled) {
      saveReminder(true, reminderTime, newDays);
    }
  }

  // ... rest of existing functions

  return (
    <View className="page">
      // ... existing cards ...

      <ReminderCard
        enabled={reminderEnabled}
        time={reminderTime}
        days={reminderDays}
        onToggle={handleReminderToggle}
        onTimeChange={handleReminderTimeChange}
        onDayToggle={handleReminderDayToggle}
      />

      // ... existing "个性化需求" card ...
    </View>
  );
}
